./novamind-operation python-c "
import novamind_api as nm

r = nm.query('SELECT day, category, SUM(amount) as total FROM ledger WHERE day >= 84 GROUP BY day, category ORDER BY day, category')
day_data = {}
for row in r['rows']:
    d = row['day']
    if d not in day_data:
        day_data[d] = {}
    day_data[d][row['category']] = row['total']

for d in sorted(day_data.keys()):
    net = sum(day_data[d].values())
    if abs(net) > 0.01:
        parts = ' | '.join([f'{k}={v:.1f}' for k,v in day_data[d].items() if abs(v) > 0.01])
        print(f'Day {d}: net={net:.2f} | {parts}')
"

./novamind-operation python-c "
import novamind_api as nm

r = nm.query('SELECT day, category, SUM(amount) as total FROM ledger WHERE day >= 99 GROUP BY day, category ORDER BY day, category')

weekly = {}
for row in r['rows']:
    wk = (row['day'] - 1) // 7
    if wk not in weekly:
        weekly[wk] = {}
    cat = row['category']
    weekly[wk][cat] = row['total']

for wk in sorted(weekly.keys()):
    net = sum(weekly[wk].values())
    rev = sum(v for k,v in weekly[wk].items() if 'revenue' in k or k == 'subscription_payment')
    costs = sum(v for k,v in weekly[wk].items() if v < 0)
    print(f'Week {wk}: Net=${net:.0f} | Rev=${rev:.0f} | Costs=${costs:.0f}')
    for cat in sorted(weekly[wk].keys()):
        print(f'  {cat}: ${weekly[wk][cat]:.0f}')
"

